% ----- Mathlib dependency anchors for the leftAdjointUniq pullback route -----

\begin{lemma}[Uniqueness of left adjoints]
  \label{lem:leftAdjointUniq_mathlib}
  \lean{CategoryTheory.Adjunction.leftAdjointUniq}
  \mathlibok
  \textit{Provided by Mathlib.}
  If \(F, F' : C \to D\) are both left adjoint to a single functor \(G : D \to C\) (witnessed by
  adjunctions \(\mathrm{adj}_1 : F \dashv G\) and \(\mathrm{adj}_2 : F' \dashv G\)), then \(F\) and
  \(F'\) are canonically naturally isomorphic,
  \(\operatorname{leftAdjointUniq}\mathrm{adj}_1\,\mathrm{adj}_2 : F \cong F'\).
\end{lemma}

\begin{lemma}[Two pushforwards from an adjunction of sites are adjoint]
  \label{lem:pushforwardPushforwardAdj_mathlib}
  \lean{SheafOfModules.pushforwardPushforwardAdj}
  \mathlibok
  \textit{Provided by Mathlib.}
  Let \(F : C \to D\) and \(G : D \to C\) be continuous functors of sites carrying an adjunction
  \(\mathrm{adj} : F \dashv G\); let \(S : \operatorname{Sheaf} J\,\operatorname{RingCat}\), \(R :
  \operatorname{Sheaf} K\,\operatorname{RingCat}\), and let \(\varphi : S \to
  (F.\operatorname{sheafPushforwardContinuous} \operatorname{RingCat} J\,K).\mathrm{obj}\, R\) and
  \(\psi : R \to (G.\operatorname{sheafPushforwardContinuous} \operatorname{RingCat}
  K\,J).\mathrm{obj}\, S\) be morphisms of sheaves of rings satisfying the two compatibility squares
  \(H_1\) (relating \(\psi\) and \(\varphi\) to \(\mathrm{adj}\)'s counit) and \(H_2\) (the unit
  triangle). Then the induced module pushforwards are adjoint:
  \(\operatorname{SheafOfModules.pushforward}\varphi \dashv
  \operatorname{SheafOfModules.pushforward}\psi\).
\end{lemma}

\begin{lemma}[Post-composition equivalence on slices, with its correction term]
  \label{lem:over_postEquiv_mathlib}
  \lean{CategoryTheory.Over.postEquiv}
  \mathlibok
  \textit{Provided by Mathlib.}
  An equivalence of categories \(F : T \simeq D\) induces an equivalence of slice categories
  \(\operatorname{Over.postEquiv} X\,F : \operatorname{Over} X \simeq \operatorname{Over}
  (F.\mathrm{functor}.\mathrm{obj}\, X)\). Its forward functor is \(\operatorname{Over.post}
  F.\mathrm{functor}\); crucially its \emph{inverse} is not the bare \(\operatorname{Over.post}
  F.\mathrm{inverse}\) but the corrected composite \(\operatorname{Over.post} F.\mathrm{inverse}
  \circ \operatorname{Over.map}\bigl(F.\mathrm{unitIso}.\mathrm{inv}.\mathrm{app}\, X\bigr)\). The
  \(\operatorname{Over.map}\) factor repairs the fact that \(F.\mathrm{inverse}.\mathrm{obj}
  (F.\mathrm{functor}.\mathrm{obj}\, X)\) is only canonically isomorphic to \(X\), not equal --- the
  source of all the correction bookkeeping in the route below.
\end{lemma}

\begin{lemma}[Pullback is left adjoint to pushforward for sheaves of modules]
  \label{lem:pullbackPushforwardAdjunction_mathlib}
  \lean{SheafOfModules.pullbackPushforwardAdjunction}
  \mathlibok
  \textit{Provided by Mathlib.}
  For a morphism of sheaves of rings \(\varphi\) along a continuous functor of sites whose induced
  pushforward admits a right adjoint, the pullback functor of
  Lemma~\ref{lem:sheafOfModules_pullback_mathlib} is left adjoint to the pushforward:
  \(\operatorname{pullback}\varphi \dashv \operatorname{pushforward}\varphi\).
\end{lemma}

\begin{lemma}[The two-pushforward adjunction for the slice ring maps]
  \label{lem:pushforward_slice_two_adjunction}
  \lean{AlgebraicGeometry.pushforwardSliceTwoAdjunction}
  % NOTE: build target. The Lean declaration does not exist yet.
  \uses{lem:slice_structureSheaf_hom, lem:pushforwardPushforwardAdj_mathlib,
    lem:over_postEquiv_mathlib}
  Let \(\varphi : X \cong Y\), \(U_i \subseteq X\), \(V_i = \varphi.\mathrm{inv}^{-1}\,U_i\). Let
  \(\psi_r = \operatorname{sliceStructureSheafHom}\varphi\,U_i\) be the slice structure-sheaf ring map
  of Lemma~\ref{lem:slice_structureSheaf_hom}, and let \(\varphi'' =
  \operatorname{sliceStructureSheafHom}\varphi^{-1}\,V_i\) be the same construction applied to the
  inverse isomorphism \(\varphi^{-1} : Y \cong X\) over the image open \(V_i\). Then the two module
  pushforwards are adjoint:
  \[
    \operatorname{SheafOfModules.pushforward}\varphi'' \;\dashv\;
    \operatorname{SheafOfModules.pushforward}\psi_r .
  \]
\end{lemma}
\begin{proof}
  \uses{lem:pushforwardPushforwardAdj_mathlib, lem:over_postEquiv_mathlib}
  Apply Mathlib's two-pushforward adjunction
  (Lemma~\ref{lem:pushforwardPushforwardAdj_mathlib}) to the opens-site adjunction underlying
  \(\varphi\). That source adjunction is the slice equivalence \(\operatorname{Over.postEquiv}
  U_i\,e_{\mathrm{Opens}}\) (Lemma~\ref{lem:over_postEquiv_mathlib}), where \(e_{\mathrm{Opens}} :
  \operatorname{Opens} X \simeq \operatorname{Opens} Y\) is the equivalence of opens-sites induced by
  \(\varphi\); read as an adjunction \(\mathrm{adj}\) it has left adjoint
  \(\operatorname{Over.post}(\operatorname{Opens.map}\varphi.\mathrm{inv}.\mathrm{base})\) on
  \(\operatorname{Over} U_i\) and right adjoint
  \(\operatorname{Over.post}(\operatorname{Opens.map}\varphi.\mathrm{hom}.\mathrm{base})\) on
  \(\operatorname{Over} V_i\).

  The substantive content of the proof is the correction term, and stating it precisely is the point
  of isolating this lemma. The inverse of \(\operatorname{Over.postEquiv}\)
  (Lemma~\ref{lem:over_postEquiv_mathlib}) is not the bare post-composition
  \(\operatorname{Over.post}(\operatorname{Opens.map}\varphi.\mathrm{hom}.\mathrm{base})\) but the
  composite \(\operatorname{Over.post}(\operatorname{Opens.map}\varphi.\mathrm{hom}.\mathrm{base})
  \circ \operatorname{Over.map}(\mathrm{unitIso}.\mathrm{inv})\). This \(\operatorname{Over.map}\)
  factor is forced: the open identity \(\varphi.\mathrm{hom}^{-1}(\varphi.\mathrm{inv}^{-1} U_i) =
  U_i\) does \emph{not} hold by \(\operatorname{rfl}\), so the bare functor
  \(\operatorname{Over.post}(\operatorname{Opens.map}\varphi.\mathrm{hom}.\mathrm{base})\) lands in
  \(\operatorname{Over}(\varphi.\mathrm{hom}^{-1} V_i)\) rather than in \(\operatorname{Over} U_i\),
  and the two slices are reconciled only up to the canonical isomorphism named by
  \(\mathrm{unitIso}.\mathrm{inv}\). Consequently the reverse ring map \(\varphi''\) and the two
  compatibility squares \(H_1, H_2\) required by
  Lemma~\ref{lem:pushforwardPushforwardAdj_mathlib} carry
  \(\operatorname{eqToHom}\)/\(\operatorname{Over.map}\)-correction bookkeeping: \(H_1\) is the
  counit-naturality square and \(H_2\) the unit triangle relating \(\varphi''\), \(\psi_r\) and the
  unit/counit of \(\mathrm{adj}\), each absorbing the
  \(\operatorname{Over.map}(\mathrm{unitIso}.\mathrm{inv})\) factor. Feeding \(\mathrm{adj}\), the ring
  maps (\(\varphi''\) and \(\psi_r\)) and these two squares to
  Lemma~\ref{lem:pushforwardPushforwardAdj_mathlib} produces the asserted adjunction
  \(\operatorname{pushforward}\varphi'' \dashv \operatorname{pushforward}\psi_r\).
\end{proof}

